{
  "executive_summary": "Payment processing service with customer-managed encryption keys (CMK), sub-50ms P99 latency, full audit logging, offline resilience, and zero-downtime key rotation. The core architectural insight is that these requirements contain fundamental tensions — particularly between external CMK dependency and offline operation, and between field-level audit logging and 50ms P99 latency. The design resolves these through envelope encryption with locally cached Data Encryption Keys (DEKs), asynchronous audit pipelines, and a dual-key architecture that supports graceful KMS degradation.",

  "architecture": {
    "components": [
      {
        "name": "Payment Gateway",
        "responsibility": "Accepts inbound payment requests, validates input, routes to processing pipeline. Stateless HTTP/gRPC endpoint.",
        "boundaries": "No direct access to encryption keys or raw payment data persistence. Delegates all crypto to Encryption Envelope Service."
      },
      {
        "name": "Encryption Envelope Service",
        "responsibility": "Implements envelope encryption pattern. Generates DEKs locally, wraps them with CMK-derived Key Encryption Keys (KEKs). Manages local DEK cache with TTL. Performs all encrypt/decrypt operations in-process.",
        "boundaries": "Owns the cryptographic boundary. Never exposes raw DEKs outside process memory. Communicates with KMS Adapter for KEK operations only."
      },
      {
        "name": "KMS Adapter",
        "responsibility": "Anti-corruption layer between internal key model and external customer KMS (AWS KMS, Azure Key Vault, GCP Cloud KMS, HashiCorp Vault). Handles key wrapping/unwrapping, connection pooling, circuit breaking, and KMS-specific translation.",
        "boundaries": "Only component aware of external KMS specifics. Exposes a uniform internal KeyProvider interface. Never touches payment data."
      },
      {
        "name": "Local Key Cache",
        "responsibility": "Encrypted in-memory cache of wrapped DEKs and their plaintext counterparts (in secure memory). Provides offline resilience when KMS is unreachable. Supports configurable TTL and max-key limits.",
        "boundaries": "Keys stored in mlock'd memory pages (non-swappable). Cache entries are evicted on TTL expiry or rotation signal. Cache is NOT persisted to disk — on cold start with KMS down, service enters degraded mode."
      },
      {
        "name": "Payment Processor",
        "responsibility": "Core payment logic — authorization, capture, settlement orchestration. Operates on decrypted payment data in-memory only.",
        "boundaries": "Never persists raw PAN/CVV. Receives decrypted data from Encryption Envelope Service, processes, then hands encrypted result back for storage."
      },
      {
        "name": "Audit Pipeline",
        "responsibility": "Captures field-level access events asynchronously via in-process ring buffer. Batches and flushes to durable audit store. Guarantees at-least-once delivery with local WAL spillover.",
        "boundaries": "Append-only. Audit records are themselves encrypted with a separate audit KEK. No read-path queries in the hot payment path."
      },
      {
        "name": "Key Rotation Orchestrator",
        "responsibility": "Manages 30-day key rotation lifecycle. Generates new DEKs, re-wraps with new KEK versions, coordinates background re-encryption of data at rest. Tracks rotation state per customer/key-scope.",
        "boundaries": "Operates asynchronously from payment processing. Uses double-write pattern during rotation window so both old and new keys decrypt successfully."
      },
      {
        "name": "Encrypted Payment Store",
        "responsibility": "Persists encrypted payment records with key metadata (key ID, key version, algorithm, IV/nonce). Supports querying by non-sensitive indexed fields.",
        "boundaries": "Never contains plaintext sensitive data. Each record carries its own encryption metadata for independent decryptability."
      }
    ],
    "interfaces": [
      {
        "from": "Payment Gateway",
        "to": "Encryption Envelope Service",
        "contract": "encrypt(plaintext, customerKeyScope) → {ciphertext, keyId, keyVersion, nonce}; decrypt(encryptedPayload) → plaintext",
        "coupling_type": "synchronous, in-process function call — tight but intentional for latency"
      },
      {
        "from": "Encryption Envelope Service",
        "to": "KMS Adapter",
        "contract": "wrapKey(dek, customerKeyScope) → wrappedDek; unwrapKey(wrappedDek, customerKeyScope) → dek",
        "coupling_type": "synchronous with circuit breaker fallback to Local Key Cache"
      },
      {
        "from": "KMS Adapter",
        "to": "External KMS",
        "contract": "Customer-specific KMS API (AWS Encrypt/Decrypt, Vault Transit, etc.)",
        "coupling_type": "network call — loosely coupled via adapter pattern, protected by circuit breaker"
      },
      {
        "from": "Encryption Envelope Service",
        "to": "Local Key Cache",
        "contract": "get(keyId) → CachedKey | miss; put(keyId, dek, wrappedDek, ttl)",
        "coupling_type": "in-process, synchronous — memory-only"
      },
      {
        "from": "Payment Gateway",
        "to": "Audit Pipeline",
        "contract": "emit(AuditEvent{timestamp, actor, field, operation, paymentRef, keyId})",
        "coupling_type": "asynchronous — fire-and-forget into ring buffer, zero back-pressure on hot path"
      },
      {
        "from": "Key Rotation Orchestrator",
        "to": "Encryption Envelope Service",
        "contract": "rotateKeys(customerKeyScope, newKeyVersion); getRotationState(customerKeyScope) → RotationStatus",
        "coupling_type": "asynchronous command, background process"
      },
      {
        "from": "Key Rotation Orchestrator",
        "to": "Encrypted Payment Store",
        "contract": "streamRecordsForReEncryption(customerKeyScope, oldKeyVersion) → Stream<EncryptedRecord>",
        "coupling_type": "batch/streaming — background, rate-limited to avoid impact on live traffic"
      }
    ],
    "data_flow": "1) Payment Gateway receives request → 2) Encryption Envelope Service encrypts PAN/CVV using cached DEK (or generates new DEK + wraps via KMS Adapter on cache miss) → 3) Payment Processor executes authorization on decrypted data in-memory → 4) Encrypted result persisted to Payment Store with key metadata → 5) Audit events emitted asynchronously at each field access point → 6) Key Rotation Orchestrator runs on schedule, re-encrypting records in background batches. CRITICAL PATH for latency: steps 1-4 must complete within 50ms P99. KMS calls are OFF the critical path except on cold-start cache miss.",
    "patterns_used": [
      {
        "pattern": "Envelope Encryption",
        "rationale": "Decouples high-frequency data encryption (local DEK, fast AES-256-GCM) from low-frequency key management (remote KMS for KEK). This is THE key pattern that makes 50ms P99 feasible with CMK — the CMK never directly encrypts data, only wraps/unwraps DEKs."
      },
      {
        "pattern": "Circuit Breaker with Local Fallback",
        "rationale": "KMS Adapter uses circuit breaker (closed → open → half-open). When open, falls back to Local Key Cache for already-cached DEKs, enabling offline operation. New customers/keys without cached DEKs enter graceful degradation."
      },
      {
        "pattern": "Async Audit via Ring Buffer + WAL",
        "rationale": "Field-level audit logging on every access would add 5-15ms if synchronous. Instead, audit events are written to a lock-free ring buffer (LMAX Disruptor pattern), then flushed asynchronously. A write-ahead log on local disk provides durability guarantee without blocking the payment path."
      },
      {
        "pattern": "Double-Write Key Rotation",
        "rationale": "During rotation window, records are readable with both old and new key versions. New writes use new DEK. Background process re-encrypts old records. No maintenance window needed because both key versions coexist."
      },
      {
        "pattern": "Anti-Corruption Layer (KMS Adapter)",
        "rationale": "Each customer may use a different KMS provider. The adapter translates between our internal KeyProvider interface and provider-specific APIs, preventing KMS vendor lock-in from leaking into core domain."
      },
      {
        "pattern": "Secure Memory (mlock)",
        "rationale": "DEK plaintext held in mlock'd memory pages to prevent swapping to disk. Zeroed on eviction. Mitigates cold-boot and swap-file attack vectors."
      }
    ]
  },

  "domain_model": {
    "bounded_contexts": [
      {
        "name": "Payment Processing",
        "classification": "core",
        "aggregates": [
          "Payment (root: PaymentId — contains PaymentMethod value object, Amount value object, ProcessingResult entity)",
          "PaymentSession (root: SessionId — tracks lifecycle from initiation to settlement)"
        ]
      },
